mapper.select:
/* oms-po-SubicPoPlanReq-sql-oracle.xml - selectTOrderSubicPoPlanReqCount */
SELECT COUNT(*) FROM ( SELECT I.OWKEY , IC.CTKEY -- 상품정보 , I.ICKEY , I.ICNM , I.UNICYN , I.SLPRC , I.ACKEY , AC.ACNM , SO.SOHDKEY , IC.LCKEY , S_ICUT.IC_EA AS ICEA , S_ICUT.IC_BND AS ICBND , S_ICUT.IC_PLT AS ICPLT , I.POABLEYN -- 발주구역 , LC.ANSUNGB2BPOCTG , LC.NAMSAB2BPOCTG , LC.BUSANB2BPOCTG -- 일평균 출고량 , COALESCE(AV.QTY, 0) AS EADAYAVGOBQTY --일평균수량 , TRUNC(COALESCE(AV.QTY, 0) / IC_BND) AS BNDDAYAVGOBQTY , TRUNC(COALESCE(AV.QTY, 0) / IC_PLT) AS PLTDAYAVGOBQTY -- 월평균 출고량 (집계테이블 생성 필요 : 배치) , COALESCE(ST.QTY, 0) AS EAMONTHAVGOBQTY -- 월평균수량 , TRUNC(COALESCE(ST.QTY, 0) / IC_BND) AS BNDMONTHAVGOBQTY , TRUNC(COALESCE(ST.QTY, 0) / IC_PLT) AS PLTMONTHAVGOBQTY
-- 온라인 재고 정보 , COALESCE(RIV.AVQTY, 0) AS AVQTY , COALESCE(RIV.AVQTY, 0) AS TOTQTY
-- 발주 가용일 산정 , COALESCE(RE.CTLEADTIME, COALESCE(I.LEADTIME, 0)) AS CTLEADTIME -- 부자재는 거래처 리드타임을 보아야 한다. , COALESCE(RE.AVDAYS, RO.NEEDDAYS) AS AVDAYS , COALESCE(RE.CALAVDAYS, TRUNC((COALESCE(RIV.AVQTY, 0)) / NULLIF(COALESCE(AV.QTY, 0),0))) AS NOWCNVRTAVDAYS -- 계산식 필요컬럼 , COALESCE(AV.QTY, 0) AS AVGQTY
--발주 필요 가능일 : (가용일 + 센터 리드타임) - 현재 환산 가용일 [현재 환산가용일 : 총재고 / 일평균수량] , (COALESCE(RE.CTLEADTIME, COALESCE(I.LEADTIME, 0)) + COALESCE(RE.AVDAYS, RO.NEEDDAYS)) - COALESCE(RE.CALAVDAYS, TRUNC(COALESCE(RIV.AVQTY, 0) / NULLIF(COALESCE(AV.QTY, 1),0))) AS PONEEDDAYS --발주요청 데이터 , RE.REQORDERUNIT -- 발주단위 , RE.DLVYREQORDERUNIT -- 배송용기단위 , RE.REQORDERQTY -- 발주요청수량 , COALESCE(REQORDERDAY, TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd')) AS REQORDERDAY , 'N' AS URGENCYREQORDERYN , COALESCE(RE.REQORDERAR, '') AS REQORDERAR , COALESCE(RE.REQORDERTYPE, '04') AS REQORDERTYPE -- 03 : 이고발주 , COALESCE(RE.REQORDEREXCEPTYN, 'N') AS REQORDEREXCEPTYN , RE.REQORDERSTATUS , RE.REQORDERNO , COALESCE(RE.SEQ, 1) AS SEQ , OBAVG.OBFROMDAY , OBAVG.OBTODAY , OBAVG.APLYDAYS
, RE.INSERTDATE , RE.INSERTURKEY , RE.UPDATEDATE , RE.UPDATEURKEY FROM TORDER_MST_IC I INNER JOIN TORDER_MST_ICXCT IC ON I.OWKEY = IC.OWKEY AND I.ICKEY = IC.ICKEY INNER JOIN TORDER_MST_CT CT ON IC.CTKEY = CT.CTKEY INNER JOIN ( SELECT ICKEY , OWKEY , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'EA' THEN ICUNITQTY END), 1) AS IC_EA , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'BND' THEN ICUNITQTY END), 1) AS IC_BND , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'PLT' THEN ICUNITQTY END), 1) AS IC_PLT FROM TORDER_MST_ICUTXTYPE WHERE OWKEY = 'DAISO' GROUP BY ICKEY, OWKEY ) S_ICUT ON I.OWKEY = S_ICUT.OWKEY AND I.ICKEY = S_ICUT.ICKEY INNER JOIN TORDER_MST_REQORDER RO ON IC.OWKEY = RO.OWKEY AND IC.CTKEY = RO.CTKEY AND IC.ICKEY = RO.ICKEY INNER JOIN TORDER_MST_AC AC ON I.OWKEY = AC.OWKEY AND I.ACKEY = AC.ACKEY AND AC.DELYN = 'N' LEFT JOIN TORDER_INFO_OBSTAT_AVG AV ON IC.OWKEY = AV.OWKEY AND IC.CTKEY = AV.CTKEY AND IC.ICKEY = AV.ICKEY LEFT JOIN ( SELECT OWKEY, CTKEY, ICKEY , TRUNC(SUM(QTY) / 30) AS QTY FROM TORDER_INFO_ORDER_STAT WHERE CRITDAY BETWEEN TO_CHAR(CURRENT_TIMESTAMP - INTERVAL '30 days', 'yyyyMMdd') AND TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') GROUP BY OWKEY, CTKEY, ICKEY ) ST ON IC.OWKEY = ST.OWKEY AND IC.CTKEY = ST.CTKEY AND IC.ICKEY = ST.ICKEY LEFT JOIN TORDER_INFO_REQORDERIV RIV ON IC.OWKEY = RIV.OWKEY AND IC.CTKEY = RIV.CTKEY AND IC.ICKEY = RIV.ICKEY LEFT JOIN TORDER_INFO_REQORDER RE ON IC.OWKEY = RE.OWKEY AND IC.CTKEY = RE.CTKEY AND IC.ICKEY = RE.ICKEY AND RE.REQORDERDAY = TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') AND RE.URGENCYREQORDERYN = 'N' LEFT JOIN TORDER_INFO_SO_HD SO ON RE.OWKEY = SO.OWKEY AND RE.REQORDERNO = SO.RFRNCKEY AND RE.IBEXPCTDAY = SO.DLVYEXPCTDAY AND SO.WKSTATUS != #{soCancelStatus} LEFT JOIN TORDER_MST_LC LC ON IC.CTKEY = LC.CTKEY AND IC.LCKEY = LC.LCKEY LEFT JOIN TORDER_MST_OBAVGQTY OBAVG ON IC.OWKEY = OBAVG.OWKEY AND IC.CTKEY = OBAVG.CTKEY AND IC.ICKEY = OBAVG.ICKEY WHERE I.POABLEYN = 'Y' AND RO.REQORDERTYPE = '04' -- REQORDERTYPE : 04(부자재)
AND I.OWKEY = #{OWKEY}
AND IC.CTKEY = #{CTKEY}
AND IC.ICKEY IN
#{item}
AND RE.REQORDERSTATUS = #{REQORDERSTATUS}
AND RE.REQORDEREXCEPTYN = #{REQORDEREXCEPTYN}
) F
1 = 1
AND F.PONEEDDAYS <= 0
AND F.PONEEDDAYS > 0
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY F.UPDATEDATE DESC NULLS LAST, F.ICKEY ASC

