mapper.update:
		/* oms-po-SubicPoPlanReq-sql-oracle.xml - updateSubicPoPlanReq */
		UPDATE TORDER_INFO_REQORDER
		   SET ICTGT            = #{ictgt}
             , REQORDERAR       = #{reqorderar}
             , REQORDERNO       = #{reqorderno}
             , REQORDERSTATUS   = #{reqorderstatus}
             , ABLEREQORDERYN   = #{ablereqorderyn}
             , UNICYN           = #{unicyn}
             , AVGOBQTY         = #{eadayavgobqty}
             , AVGOBFROMDAY     = #{avgobfromday}
             , AVGOBTODAY       = #{avgobtoday}
             , AVGAPLYDAYS      = #{avgaplydays}
             , AVQTY            = #{avqty}
             , IBEXPCTQTY       = #{b2cibqty}
             , REQCTKEY         = #{ctkey}
             , CALAVDAYS        = #{calavdays}
             , DLVYREQORDERUNIT = #{reqorderunit}
             , REQORDERQTY      = #{reqorderqty}
             , CNFRMREQORDERQTY = #{cnfrmreqorderqty}
             , AVDAYS           = #{avdays}
             , REQORDERUNIT     = #{reqorderunit}
             , CTLEADTIME       = #{CTLEADTIME}
             , UPDATEDATE       = #{sysdate}
             , UPDATEURKEY      = #{surkey}
		WHERE OWKEY             = #{owkey}
	      AND CTKEY             = #{ctkey}
	      AND REQORDERDAY       = #{reqorderday}
          AND ICKEY             = #{ickey}
          AND REQORDERTYPE      = #{reqordertype}
          AND URGENCYREQORDERYN = #{urgencyreqorderyn}
          AND SEQ               = #{seq}

mapper.insert:

	SELECT #{ibexpctday} || #{orderNoType} || LPAD(nextval('seq_torder_info_so_hd')::TEXT, 6, '0')
	-- ibexpctday 입고예정일 ( 현재날짜 + 거래처 리드타임), ackey 는 torder_mst_ic에서 조회 , orderNoType = 'S'( OrderNoTypeEnum.SO )

INSERT INTO TORDER_INFO_SO_HD
(    OWKEY
   , SOHDKEY
   , DLVYEXPCTDAY
   , ORDERISTDAY
   , ORDERTYPECD
   , WKSTATUS
   , CTKEY
   , ACKEY
   , POTYPE
   , RFRNCKEY
   , ORGORDERKEY
   , INSERTDATE
   , INSERTURKEY
   , UPDATEDATE
   , UPDATEURKEY
)  VALUES(
	 #{owkey}
   , #{sohdkey}
   , #{ibexpctday}
   , TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD')
   , '40' -- 부자재입고 (주문유형코드)
   , #{wkstatus} -- 작업생성 (주문기준코드 : SOSTATUS)
   , #{ctkey}
   , #{ackey}
   , '04' -- 발주유형 : 04(부자재)
   , #{reqorderno}
   , #{reqorderno}
   , #{insertdate}
   , #{inserturkey}
   , #{updatedate}
   , #{updateurkey}
)

